func applyPolicy(ctx context.Context,state *policyModel,item policyAPI){state.ID=types.StringValue(item.ID);state.Name=types.StringValue(item.Name);state.Kind=types.StringValue(item.Kind);if item.Description!=nil{state.Description=types.StringValue(*item.Description)}else{state.Description=types.StringNull()};state.Enabled=types.BoolValue(item.Enabled);state.Version=types.Int64Value(item.Version);raw,_:=json.Marshal(item.Document);state.Document=types.StringValue(string(raw));_ = ctx}
